120	export default function SignInPage() {
121	  const [isLoading, setIsLoading] = useState(false);
122	  const [googleLoading, setGoogleLoading] = useState(false);
123	  const [appleLoading, setAppleLoading] = useState(false);
124	  const [appleReady, setAppleReady] = useState(false);
125	  const [callbackUrl, setCallbackUrl] = useState<string | null>(null);
126	  const googleBtnRef = useRef<HTMLDivElement>(null);
127	  const googleInitialized = useRef(false);
128	
129	  useEffect(() => {
130	    if (!getIsClient()) return;
131	    const params = new URLSearchParams(window.location.search);
132	    setCallbackUrl(params.get("callbackUrl"));
133	  }, []);
134	
135	  // biome-ignore lint/correctness/useExhaustiveDependencies: initGoogle/initApple are stable guards
136	  useEffect(() => {
137	    if (window.google?.accounts?.id) initGoogle();
138	    if (window.AppleID) initApple();
139	  }, []);
140	
141	  const handleGoogleCredential = async (response: { credential: string }) => {
142	    setGoogleLoading(true);
143	    try {
144	      const result = await signIn("google-oauth", {
145	        idToken: response.credential,
146	        redirect: false,
147	      });
148	
149	      if (result?.ok) {
150	        const params = new URLSearchParams(window.location.search);
151	        hardPush(params.get("callbackUrl") || APP_ROUTES.APP.MY_DEALS);
152	      } else {
153	        toast.error("Google Sign In Failed", {
154	          description: "Please try again",
155	        });
156	        setGoogleLoading(false);
157	      }
158	    } catch {
159	      toast.error("Google Sign In Failed", {
160	        description: "An unexpected error occurred",
161	      });
162	      setGoogleLoading(false);
163	    }
164	  };
165	
166	  const handleAppleSignIn = async () => {
167	    if (!appleReady || !window.AppleID) return;
168	    setAppleLoading(true);
169	    try {
170	      const response = await window.AppleID.auth.signIn();
171	      const identityToken = response.authorization.id_token;
172	      const firstName = response.user?.name?.firstName ?? undefined;
173	      const lastName = response.user?.name?.lastName ?? undefined;
174	
175	      const result = await signIn("apple-oauth", {
176	        identityToken,
177	        firstName: firstName ?? "",
178	        lastName: lastName ?? "",
179	        redirect: false,
180	      });
181	
182	      if (result?.ok) {
183	        const params = new URLSearchParams(window.location.search);
184	        hardPush(params.get("callbackUrl") || APP_ROUTES.APP.MY_DEALS);
185	      } else {
186	        toast.error("Apple Sign In Failed", {
187	          description: "Please try again",
188	        });
189	        setAppleLoading(false);
190	      }
191	    } catch {
192	      toast.error("Apple Sign In Failed", {
193	        description: "An unexpected error occurred",
194	      });
195	      setAppleLoading(false);
196	    }
197	  };
198	
199	  const initApple = () => {
200	    if (!window.AppleID || !process.env.NEXT_PUBLIC_APPLE_CLIENT_ID) return;
201	    window.AppleID.auth.init({
202	      clientId: process.env.NEXT_PUBLIC_APPLE_CLIENT_ID,
203	      scope: "name email",
204	      redirectURI: process.env.NEXT_PUBLIC_APP_URL ?? window.location.origin,
205	      usePopup: true,
206	    });
207	    setAppleReady(true);
208	  };
209	
210	  const initGoogle = () => {
211	    const google = window.google;
212	    if (
213	      !google?.accounts?.id ||
214	      !googleBtnRef.current ||
215	      googleInitialized.current
216	    )
217	      return;
218	    googleInitialized.current = true;
219	    google.accounts.id.initialize({
220	      client_id: process.env.NEXT_PUBLIC_GOOGLE_CLIENT_ID,
221	      callback: handleGoogleCredential,
222	    });
223	    google.accounts.id.renderButton(googleBtnRef.current, {
224	      type: "standard",
225	      theme: "outline",
226	      size: "large",
227	      width: googleBtnRef.current.offsetWidth || 200,
228	    });
229	  };
230	
231	  const form = useForm<LoginFormData>({
232	    resolver: zodResolver(loginSchema),
233	    defaultValues: { email: "", password: "" },
234	  });
235	
236	  const onSubmit = async (data: LoginFormData) => {
237	    setIsLoading(true);
238	    try {
239	      const result = await signIn("credentials", {
240	        email: data.email,
241	        password: data.password,
242	        redirect: false,
243	      });
244	
245	      if (result?.error) {
246	        toast.error("Sign In Failed", {
247	          description: "Invalid email or password",
248	        });
249	        return;
250	      }
251	
252	      if (result?.ok) {
253	        hardPush(callbackUrl || APP_ROUTES.APP.MY_DEALS);
254	      }
255	    } catch {
256	      toast.error("Sign In Failed", {
257	        description: "An unexpected error occurred",
258	      });
259	    } finally {
260	      setIsLoading(false);
261	    }
262	  };
263	
264	  return (
265	    <>
266	      <Script
267	        src="https://accounts.google.com/gsi/client"
268	        strategy="afterInteractive"
269	        onLoad={initGoogle}
270	      />
271	      <Script
272	        src="https://appleid.cdn-apple.com/appleauth/static/jsapi/appleid/1/en_US/appleid.auth.js"
273	        strategy="afterInteractive"
274	        onLoad={initApple}
275	      />
276	      <div className="flex w-full flex-col gap-5">
277	        {/* Header */}
278	        <div className="flex flex-col">
279	          <h1 className="font-light font-new-serif text-[#44403C] text-xl leading-[140%]">
280	            Welcome Back
281	          </h1>
282	          <p className="font-new-sans text-[#44403C] text-sm leading-[150%] tracking-[-0.01em]">
283	            Login to your account to access LuxFlow
284	          </p>
285	        </div>
286	
287	        {/* Social Buttons */}
288	        <div className="flex flex-col gap-2 sm:flex-row">
289	          {/* Google */}
290	          <div className="relative h-12 w-full sm:flex-1">
291	            <div className="pointer-events-none flex h-12 w-full items-center justify-center gap-2 rounded-[4px] border border-[#A8A29E] bg-[#F5F3EF] px-4 py-3 font-medium font-new-sans text-[#44403C] text-sm tracking-[-0.01em]">
292	              <GoogleIcon />
293	              <span className="whitespace-nowrap">
294	                {googleLoading ? "..." : "Google"}
295	              </span>
296	            </div>
297	            <div
298	              ref={googleBtnRef}
299	              className="absolute inset-0 overflow-hidden opacity-0"
300	            />
301	          </div>
302	
303	          {/* Apple */}
304	          <button
305	            type="button"
306	            onClick={handleAppleSignIn}
307	            disabled={appleLoading || !appleReady}
308	            className="flex h-12 w-full items-center justify-center gap-2 rounded-[4px] border border-[#A8A29E] bg-[#F5F3EF] px-4 py-3 font-medium font-new-sans text-[#44403C] text-sm tracking-[-0.01em] transition-opacity hover:opacity-80 disabled:cursor-not-allowed disabled:opacity-70 sm:flex-1"
309	          >
310	            <AppleIcon />
311	            <span className="whitespace-nowrap">
312	              {appleLoading ? "..." : "Apple"}
313	            </span>
314	          </button>
315	
316	          {/* UAE Pass — disabled */}
317	          <button
318	            type="button"
319	            disabled
320	            className="flex h-12 w-full cursor-not-allowed items-center justify-center gap-2 rounded-[4px] border border-[#A8A29E] bg-[#F5F3EF] px-4 py-3 font-medium font-new-sans text-[#44403C] text-sm tracking-[-0.01em] opacity-70 sm:flex-1"
321	          >
322	            <UaePassIcon />
323	            <span className="whitespace-nowrap">UAE Pass</span>
324	          </button>
325	        </div>
326	
327	        {/* Form Section */}
328	        <div className="flex flex-col gap-5">
329	          {/* OR Divider */}
330	          <div className="flex items-center gap-4">
331	            <div className="flex-1 border-[#D6D3D1] border-t" />
332	            <span className="font-bold font-new-sans text-[#A8A29E] text-sm tracking-[-0.01em]">
333	              OR
334	            </span>
335	            <div className="flex-1 border-[#D6D3D1] border-t" />
336	          </div>
337	
338	          <Form {...form}>
339	            <form
340	              onSubmit={form.handleSubmit(onSubmit)}
341	              className="flex flex-col gap-5"
342	            >
343	              <div className="flex flex-col gap-2">
344	                {/* Email */}
345	                <FormField
346	                  control={form.control}
347	                  name="email"
348	                  render={({ field }) => (
349	                    <FormItem>
350	                      <FormLabel className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
351	                        Email
352	                      </FormLabel>
353	                      <FormControl>
354	                        <Input
355	                          placeholder="Enter your email"
356	                          type="email"
357	                          className="h-12 rounded-[4px] border-[#A8A29E] bg-[#F5F3EF] px-3 font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E]"
358	                          {...field}
359	                        />
360	                      </FormControl>
361	                      <FormMessage />
362	                    </FormItem>
363	                  )}
364	                />
365	
366	                {/* Password */}
367	                <FormField
368	                  control={form.control}
369	                  name="password"
370	                  render={({ field }) => (
371	                    <FormItem>
372	                      <FormLabel className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
373	                        Password
374	                      </FormLabel>
375	                      <FormControl>
376	                        <PasswordInput
377	                          placeholder="Placeholder"
378	                          containerClassName="h-12 rounded-[4px] border-[#A8A29E] bg-[#F5F3EF] px-3"
379	                          className="font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E]"
380	                          {...field}
381	                        />
382	                      </FormControl>
383	                      <div className="flex justify-end">
384	                        <Link
385	                          href={APP_ROUTES.AUTH.REQUEST_FORGOT_PASSWORD}
386	                          className="font-new-sans text-[#000944] text-xs leading-[130%] transition-opacity hover:opacity-70"
387	                        >
388	                          Forgot Password
389	                        </Link>
390	                      </div>
391	                      <FormMessage />
392	                    </FormItem>
393	                  )}
394	                />
395	              </div>
396	
397	              {/* Login Button */}
398	              <button
399	                type="submit"
400	                disabled={isLoading}
401	                className="flex h-12 w-full items-center justify-center rounded-[4px] bg-[#021171] font-medium font-new-sans text-[#F5F3EF] text-base transition-opacity hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-70"
402	              >
403	                {isLoading ? "Signing In..." : "Login"}
404	              </button>
405	
406	              {/* Sign up link */}
407	              <p className="text-center font-new-sans text-[#44403C] text-sm leading-[150%] tracking-[-0.01em]">
408	                New to LuxFlow.{" "}
409	                <Link
410	                  href={APP_ROUTES.AUTH.REGISTER}
411	                  className="font-semibold text-[#44403C] hover:opacity-70"
412	                >
413	                  Create an Account
414	                </Link>
415	              </p>
416	            </form>
417	          </Form>
418	        </div>
419	      </div>
420	    </>
421	  );
