7	import { APP_ROUTES } from "@/shared/config/app-routes";
8	import { SELLER_SIDEBAR_ITEMS } from "@/shared/config/sidebar-config";
9	import { useSidebarContext } from "@/shared/contexts/sidebar-context";
10	import { Sidebar } from "@/shared/ui/sidebar";
11	
12	const NEW_DESIGN_ROUTES = [
13	  "/wallet",
14	  "/quote-request/create",
15	  "/my-offers",
16	  "/quote-request",
17	  "/buybacks",
18	  "/tickets",
19	  "/welcome",
20	];
21	
22	export default function SidebarLayout({ children }: { children: ReactNode }) {
23	  const router = useRouter();
24	  const pathname = usePathname();
25	  const { isOpen, setIsOpen } = useSidebarContext();
26	
27	  const isBuybackPayPage =
28	    pathname.startsWith("/buybacks/") && pathname.endsWith("/pay");
29	
30	  if (
31	    NEW_DESIGN_ROUTES.some((route) => pathname.startsWith(route)) ||
32	    isBuybackPayPage
33	  ) {
34	    return <>{children}</>;
35	  }
36	
37	  function getActiveItem() {
38	    for (const item of SELLER_SIDEBAR_ITEMS) {
39	      if (item.path === pathname) {
40	        return item.value;
41	      }
42	
43	      if (item.subItems) {
44	        for (const subItem of item.subItems) {
45	          if (subItem.path === pathname) {
46	            return subItem.value;
47	          }
48	        }
49	      }
50	    }
51	
52	    for (const item of SELLER_SIDEBAR_ITEMS) {
53	      if (item.subItems) {
54	        for (const subItem of item.subItems) {
55	          const basePath = subItem.path.split("?")[0];
56	          if (
57	            pathname.startsWith(basePath) &&
58	            (pathname[basePath.length] === "?" ||
59	              pathname[basePath.length] === "/" ||
60	              pathname.length === basePath.length)
61	          ) {
62	            return subItem.value;
63	          }
64	        }
65	      }
